// MainActivity.kt (This would be your initial login screen)
class MainActivity : AppCompatActivity() {

    private val KEY_NAME = "biometric_key"
    private val PREFS_FILE = "app_prefs"
    private val AUTH_SUCCESSFUL_KEY = "auth_successful"

    override fun onCreate(savedInstanceState: android.os.Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main) // Assuming you have an activity_main.xml

        if (isAuthenticatedSuccessfully()) {
            // User was previously authenticated, bypass login
            startActivity(Intent(this, DashboardActivity::class.java))
            finish()
            return
        }

        val biometricManager = BiometricManager.from(this)
        when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK)) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                Log.d("BIOMETRIC_APP", "App can authenticate using biometrics.")
                // Prompt biometric authentication
                promptBiometricAuthentication()
            }
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                Log.e("BIOMETRIC_APP", "No biometric features available on this device.")
                // Fallback to password login
                showPasswordLogin()
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                Log.e("BIOMETRIC_APP", "Biometric features are currently unavailable.")
                // Fallback to password login
                showPasswordLogin()
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                Log.e("BIOMETRIC_APP", "No biometric credentials enrolled.")
                // Prompt user to enroll biometrics or fallback to password
                showPasswordLogin()
            }
            else -> {
                Log.e("BIOMETRIC_APP", "Unknown biometric error.")
                // Fallback to password login
                showPasswordLogin()
            }
        }

        findViewById<android.widget.Button>(R.id.login_button).setOnClickListener {
            // Handle manual password login
            // For demo, just go to dashboard
            storeAuthenticatedSuccessfully(true)
            startActivity(Intent(this, DashboardActivity::class.java))
            finish()
        }
    }

    private fun promptBiometricAuthentication() {
        val biometricPrompt = createBiometricPrompt()
        val promptInfo = createPromptInfo()

        val cipher = try {
            initCipher()
        } catch (e: Exception) {
            Log.e("BIOMETRIC_APP", "Error initializing cipher: ${e.message}")
            showPasswordLogin() // Fallback if cipher fails
            return
        }

        biometricPrompt.authenticate(promptInfo, BiometricPrompt.CryptoObject(cipher))
    }

    private fun createBiometricPrompt(): BiometricPrompt {
        val executor = androidx.core.content.ContextCompat.getMainExecutor(this)
        return BiometricPrompt(this as FragmentActivity, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    Log.e("BIOMETRIC_APP", "Authentication error: $errString ($errorCode)")
                    showPasswordLogin() // Fallback to password login on error
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    Log.d("BIOMETRIC_APP", "Authentication succeeded!")
                    storeAuthenticatedSuccessfully(true)
                    startActivity(Intent(this@MainActivity, DashboardActivity::class.java))
                    finish()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Log.w("BIOMETRIC_APP", "Authentication failed.")
                    // User might try again, no immediate fallback to password unless too many attempts
                }
            })
    }

    private fun createPromptInfo(): BiometricPrompt.PromptInfo {
        return BiometricPrompt.PromptInfo.Builder()
            .setTitle("Fingerprint Login")
            .setSubtitle("Log in using your fingerprint")
            .setNegativeButtonText("Use Password") // Fallback button
            .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK)
            .build()
    }

    private fun showPasswordLogin() {
        // Make password fields visible, hide biometric prompt related UI
        Log.d("BIOMETRIC_APP", "Showing password login fields.")
        findViewById<android.widget.LinearLayout>(R.id.password_login_layout).visibility = android.view.View.VISIBLE
        // You might want to hide a biometric icon or message here
    }

    private fun isAuthenticatedSuccessfully(): Boolean {
        val prefs = getSharedPreferences(PREFS_FILE, Context.MODE_PRIVATE)
        return prefs.getBoolean(AUTH_SUCCESSFUL_KEY, false)
    }

    private fun storeAuthenticatedSuccessfully(authenticated: Boolean) {
        val prefs = getSharedPreferences(PREFS_FILE, Context.MODE_PRIVATE)
        with(prefs.edit()) {
            putBoolean(AUTH_SUCCESSFUL_KEY, authenticated)
            apply()
        }
    }

    // --- KeyStore and Cipher methods for secure biometric authentication ---

    private fun getKeyStore(): KeyStore {
        return KeyStore.getInstance("AndroidKeyStore").apply { load(null) }
    }

    private fun createKey() {
        try {
            val keyGenerator = KeyGenerator.getInstance(
                KeyProperties.KEY_ALGORITHM_AES,
                "AndroidKeyStore"
            )
            keyGenerator.init(
                KeyGenParameterSpec.Builder(
                    KEY_NAME,
                    KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
                )
                    .setBlockModes(KeyProperties.BLOCK_MODE_CBC)
                    .setUserAuthenticationRequired(true)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_PKCS7)
                    .build()
            )
            keyGenerator.generateKey()
        } catch (e: NoSuchAlgorithmException) {
            throw RuntimeException("Failed to create key", e)
        } catch (e: NoSuchProviderException) {
            throw RuntimeException("Failed to create key", e)
        } catch (e: InvalidAlgorithmParameterException) {
            throw RuntimeException("Failed to create key", e)
        }
    }

    private fun getCipher(): Cipher {
        return Cipher.getInstance(
            KeyProperties.KEY_ALGORITHM_AES + "/"
                    + KeyProperties.BLOCK_MODE_CBC + "/"
                    + KeyProperties.ENCRYPTION_PADDING_PKCS7
        )
    }

    private fun initCipher(): Cipher {
        val cipher = getCipher()
        val keyStore = getKeyStore()
        try {
            keyStore.load(null)
            val secretKey = keyStore.getKey(KEY_NAME, null) as SecretKey
            cipher.init(Cipher.ENCRYPT_MODE, secretKey)
            return cipher
        } catch (e: KeyPermanentlyInvalidatedException) {
            // This happens if the biometrics are removed or changed.
            // Invalidate the key and try again, or prompt for password.
            keyStore.deleteEntry(KEY_NAME)
            createKey() // Recreate key, user will re-enroll biometric
            return initCipher() // Try initializing again
        } catch (e: KeyStoreException) {
            throw RuntimeException("Failed to init Cipher", e)
        } catch (e: CertificateException) {
            throw RuntimeException("Failed to init Cipher", e)
        } catch (e: UnrecoverableKeyException) {
            throw RuntimeException("Failed to init Cipher", e)
        } catch (e: IOException) {
            throw RuntimeException("Failed to init Cipher", e)
        } catch (e: NoSuchAlgorithmException) {
            throw RuntimeException("Failed to init Cipher", e)
        } catch (e: InvalidKeyException) {
            // Key might not exist yet, create it and retry
            createKey()
            return initCipher()
        } catch (e: NoSuchPaddingException) {
            throw RuntimeException("Failed to init Cipher", e)
        }
    }
}

// DashboardActivity.kt (This is the screen shown after successful login)
class DashboardActivity : AppCompatActivity() {

    private val PREFS_FILE = "app_prefs"
    private val AUTH_SUCCESSFUL_KEY = "auth_successful"

    override fun onCreate(savedInstanceState: android.os.Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_dashboard) // Assuming you have an activity_dashboard.xml

        findViewById<android.widget.Button>(R.id.logout_button).setOnClickListener {
            // Clear the authenticated flag on logout
            clearAuthenticatedSuccessfully()
            startActivity(Intent(this, MainActivity::class.java))
            finish()
        }
    }

    private fun clearAuthenticatedSuccessfully() {
        val prefs = getSharedPreferences(PREFS_FILE, Context.MODE_PRIVATE)
        with(prefs.edit()) {
            putBoolean(AUTH_SUCCESSFUL_KEY, false)
            apply()
        }
    }
}

